define i1 @test_const_shr_and_1_ne_0(i32 %b) {
  %shr = lshr i32 42, %b
  %and = and i32 %shr, 1
  %cmp = icmp ne i32 %and, 0
  ret i1 %cmp
}

define i1 @test_shr_and_1_ne_0(i32 %a, i32 %b) {
  %shr = lshr i32 %a, %b
  %and = and i32 %shr, 1
  %cmp = icmp ne i32 %and, 0
  ret i1 %cmp
}
